  `modle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'дә§е“ҒеһӢеҸ·',
  `qsi` int NOT NULL COMMENT 'йҖҒжЈҖж•°йҮҸ (Quantity Submitted for Inspection)',
  `qi` int NOT NULL COMMENT 'жЈҖйӘҢж•°йҮҸ (Quantity Inspected)',
  `number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'дә§е“Ғзј–еҸ·',
  `flow_range` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'жөҒйҮҸиҢғеӣҙ(Flow Range)',
  `des` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'еӨҮжіЁ',
  `delete_time` datetime NULL DEFAULT NULL COMMENT 'еҲ йҷӨж—¶й—ҙ',
  `vd` int NOT NULL COMMENT 'жңүж•Ҳж•°жҚ®(valid data)',
  `insp` tinyint NOT NULL COMMENT 'жЈҖйӘҢиҝӣеәҰ(Inspection Progress)пјҡ\r\n1жңӘејҖе§ӢжЈҖйӘҢ, \r\n2зІҫеәҰеҗҲж ј, \r\n3еҠҹиғҪеҗҲж ј, \r\n4еӨ–и§ӮеҗҲж ј, \r\n5е…ЁйғЁеҗҲж ј',
  `accq_time` datetime NULL DEFAULT NULL COMMENT 'зІҫеәҰжЈҖйӘҢж—Ҙжңҹ(Accuracy qualified)',
  `funq_time` datetime NULL DEFAULT NULL COMMENT 'еҠҹиғҪжЈҖйӘҢж—Ҙжңҹ(Function qualified)',
  `appq_time` datetime NULL DEFAULT NULL COMMENT 'еӨ–и§ӮжЈҖйӘҢж—Ҙжңҹ(Appearance qualified)',
  `allq_time` datetime NULL DEFAULT NULL COMMENT 'жңҖз»Ҳе®Ўж ёж—Ҙжңҹ(All qualified)',
  `accq_uid` bigint NULL DEFAULT NULL COMMENT 'зІҫеәҰеҗҲж јжЈҖйӘҢдәә',
  `funq_uid` bigint NULL DEFAULT NULL COMMENT 'еҠҹиғҪеҗҲж јжЈҖйӘҢдәә',
  `appq_uid` bigint NULL DEFAULT NULL COMMENT 'еӨ–и§ӮеҗҲж јжЈҖйӘҢдәә',
  `allq_uid` bigint NULL DEFAULT NULL COMMENT 'жңҖз»Ҳе®Ўж ёдәә',
  `pdfstr` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'pdfең°еқҖ',
  `pdfver` int NULL DEFAULT NULL COMMENT 'PDFжҠҘе‘ҠеҚ•зүҲжң¬еҸ·',
  `cuc` double(4, 2) NULL DEFAULT NULL COMMENT 'ж•ҙжңәжңҖеӨ§з”өжөҒ 8v(Complete Unit Current)',
  `cucmax` double(4, 2) NULL DEFAULT NULL COMMENT 'ж•ҙжңәз”өжөҒ24v',
  `cucmin` double(4, 2) NULL DEFAULT NULL COMMENT 'ж•ҙжңәз”өжөҒ12v',
  `pv` double(5, 3) NULL DEFAULT NULL COMMENT 'и„үеҶІз”өеҺӢ(Pulse Voltage)',
  `thv` int NULL DEFAULT NULL COMMENT 'зғӯеӨҙз”өеҺӢ(Thermal Head Voltage)',
  `zp` int NULL DEFAULT NULL COMMENT 'йӣ¶зӮ№еҶ…з Ғ(Zero Point)',
  `fl` double(4, 2) NULL DEFAULT NULL COMMENT 'ж•…йҡңз”өе№і(Fault Level)',
  `bv` double(5, 4) NULL DEFAULT NULL COMMENT 'з”өжұ з”өеҺӢ(Battery Voltage)',
  `la` int NULL DEFAULT NULL COMMENT 'жң¬ең°ең°еқҖ(Local Address)',
  `delete_des` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'еҲ йҷӨеҺҹеӣ ',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_repid`(`report_id` ASC) USING BTREE,
  INDEX `idx_vd`(`vd` ASC) USING BTREE,
  INDEX `idx_modle`(`modle` ASC) USING BTREE,
  INDEX `idx_number`(`number` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'и®ўеҚ•йҮҢзҡ„дә§е“ҒеһӢеҸ·пјҢи·ҹжҠҘе‘ҠеҚ•еӨҡеҜ№дёҖе…ізі»' ROW_FORMAT = DYNAMIC;

